"use client";

import { useEffect, useRef } from "react";
import type { WatchParty } from "@/lib/useWatchParty";
import { useYouTubeApi, YT_STATE, type YTPlayer } from "@/lib/youtube";

/** If local time drifts from a remote target by more than this, we re-seek. */
const DRIFT_TOLERANCE = 0.75;
/** A jump larger than this between polls is treated as the user seeking. */
const SEEK_THRESHOLD = 1.25;

interface Props {
  party: WatchParty;
}

/**
 * Wraps a YouTube IFrame player and keeps it in lock-step with the room.
 *
 * Two directions:
 *  - LOCAL  -> network: detect the user pressing play/pause or seeking, and
 *    send a control message so everyone else mirrors it.
 *  - NETWORK -> local: apply control messages from other members onto the
 *    player, guarded by `applyingRemote` so we don't echo them back.
 */
export function SyncedPlayer({ party }: Props) {
  const api = useYouTubeApi();
  const containerRef = useRef<HTMLDivElement>(null);
  const playerRef = useRef<YTPlayer | null>(null);

  // Sync bookkeeping (refs so they never trigger re-renders).
  const applyingRemote = useRef(false);
  const lastTickTime = useRef(0);
  const lastTickAt = useRef(0);
  const loadedVideoId = useRef<string | null>(null);

  const room = party.room;
  const videoId = room?.videoId ?? null;
  const { sendControl, subscribeControl } = party;

  /** Run a programmatic player change without it being reported as a local action. */
  const withRemoteGuard = (fn: () => void) => {
    applyingRemote.current = true;
    fn();
    window.setTimeout(() => {
      applyingRemote.current = false;
    }, 800);
  };

  // --- Create the player once the API and container are ready. --------------
  useEffect(() => {
    if (!api || !containerRef.current || playerRef.current) return;

    const player = new api.Player(containerRef.current, {
      playerVars: { rel: 0, modestbranding: 1, playsinline: 1 },
      events: {
        onReady: () => {
          // If we joined a room that already has a video, load it in sync.
          if (room?.videoId) {
            loadVideo(player, room.videoId, room.currentTime, room.isPlaying);
          }
        },
        onStateChange: (e) => handleStateChange(e.data, e.target),
      },
    });
    playerRef.current = player;

    return () => {
      player.destroy();
      playerRef.current = null;
    };
    // We intentionally create the player once; room is read via refs/closures.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api]);

  function loadVideo(player: YTPlayer, id: string, time: number, playing: boolean) {
    loadedVideoId.current = id;
    withRemoteGuard(() => {
      if (playing) player.loadVideoById({ videoId: id, startSeconds: time });
      else player.cueVideoById({ videoId: id, startSeconds: time });
    });
  }

  // --- React to the room's video changing (someone picked a new video). -----
  useEffect(() => {
    const player = playerRef.current;
    if (!player || !videoId) return;
    if (videoId === loadedVideoId.current) return;
    loadVideo(player, videoId, room?.currentTime ?? 0, room?.isPlaying ?? false);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [videoId]);

  // --- NETWORK -> local: apply remote control actions. ----------------------
  useEffect(() => {
    const unsub = subscribeControl((action) => {
      const player = playerRef.current;
      if (!player) return;

      switch (action.kind) {
        case "play":
          withRemoteGuard(() => {
            if (Math.abs(player.getCurrentTime() - action.time) > DRIFT_TOLERANCE) {
              player.seekTo(action.time, true);
            }
            player.playVideo();
          });
          break;
        case "pause":
          withRemoteGuard(() => {
            if (Math.abs(player.getCurrentTime() - action.time) > DRIFT_TOLERANCE) {
              player.seekTo(action.time, true);
            }
            player.pauseVideo();
          });
          break;
        case "seek":
          withRemoteGuard(() => player.seekTo(action.time, true));
          break;
        case "set_video":
          // Loading a new video is handled declaratively from room.videoId.
          break;
      }
    });
    return unsub;
  }, [subscribeControl]);

  // --- LOCAL -> network: detect the user pressing play / pause. -------------
  function handleStateChange(state: number, player: YTPlayer) {
    if (applyingRemote.current) return;
    const time = player.getCurrentTime();
    if (state === YT_STATE.PLAYING) sendControl({ kind: "play", time });
    else if (state === YT_STATE.PAUSED) sendControl({ kind: "pause", time });
  }

  // --- LOCAL -> network: detect seeking by watching for time jumps. ---------
  useEffect(() => {
    const interval = window.setInterval(() => {
      const player = playerRef.current;
      if (!player || applyingRemote.current) return;
      if (typeof player.getCurrentTime !== "function") return;

      const now = Date.now();
      const actual = player.getCurrentTime();
      const playing = player.getPlayerState() === YT_STATE.PLAYING;

      if (lastTickAt.current !== 0) {
        const expected = playing
          ? lastTickTime.current + (now - lastTickAt.current) / 1000
          : lastTickTime.current;
        if (Math.abs(actual - expected) > SEEK_THRESHOLD) {
          sendControl({ kind: "seek", time: actual });
        }
      }
      lastTickTime.current = actual;
      lastTickAt.current = now;
    }, 500);
    return () => window.clearInterval(interval);
  }, [sendControl]);

  return (
    <div className="relative aspect-video w-full overflow-hidden rounded-xl bg-black">
      {/* The API replaces this div with the iframe; it must always be mounted. */}
      <div ref={containerRef} className="absolute inset-0 h-full w-full" />
      {!videoId && (
        <div className="pointer-events-none absolute inset-0 grid place-items-center text-sm text-muted-foreground">
          No video yet — search and pick one to start watching.
        </div>
      )}
    </div>
  );
}
